/*
 * events.js — World history event data for the interactive timeline (history.html)
 *
 * Data structures:
 *   ERAS[]       — time period filters (id, en label, zh label)
 *   CONTINENTS[] — geographic filters (id, en label, zh label)
 *   EVENTS[]     — main event array, each entry has:
 *     year  — integer (negative for BC)
 *     era   — must match an ERAS id
 *     cont  — must match a CONTINENTS id
 *     wiki  — Wikipedia article slug (appended to en/zh.wikipedia.org/wiki/)
 *     en    — { title, desc } in English
 *     zh    — { title, desc } in Chinese
 *     rank  — assigned at runtime by history.html (1=landmark, 2=major, 3=notable)
 *
 * To add events: append to the EVENTS array or use EVENTS.push() at the bottom.
 * Keep events sorted chronologically within each section for readability.
 */

